// Agrupa filas de credit_cases por billing_address para enviar 1 email por payer
// Input: items[] con campos como billing_address, payer_label, payer_email, owner_email, case_key, etc.
// Output: 1 item por billing_address

function safe(v) {
  return v === undefined ? null : v;
}

const groups = new Map();

for (const item of $input.all()) {
  const r = item.json;

  const billing = r.billing_address;
  if (!billing) continue;

  if (!groups.has(billing)) {
    groups.set(billing, {
      billing_address: billing,
      payer_label: r.payer_label ?? null,
      payer_email: r.payer_email ?? null,
      owner_email: r.owner_email ?? null,
      cases: [],
      case_keys: []
    });
  }

  const g = groups.get(billing);

  // Si por alguna razón payer_label / emails vienen vacíos en alguna fila, rellena con el primero no-nulo
  if (!g.payer_label && r.payer_label) g.payer_label = r.payer_label;
  if (!g.payer_email && r.payer_email) g.payer_email = r.payer_email;
  if (!g.owner_email && r.owner_email) g.owner_email = r.owner_email;

  const caseObj = {
    case_key: r.case_key,
    document_number: r.document_number,
    document_type: r.document_type,
    invoice_date: safe(r.invoice_date),
    due_date: safe(r.due_date),
    days_past_due: safe(r.days_past_due),
    open_amount: safe(r.open_amount),
    aging_bucket: safe(r.aging_bucket)
  };

  g.cases.push(caseObj);
  g.case_keys.push(r.case_key);
}

// Ordena las facturas dentro de cada payer: vencidas primero (days_past_due >= 0), luego por due_date
function parseDate(d) {
  if (!d) return null;
  const dt = new Date(d);
  return isNaN(dt.getTime()) ? null : dt.getTime();
}

const out = [];
for (const g of groups.values()) {
  g.cases.sort((a, b) => {
    const aOver = (a.days_past_due ?? -999999) >= 0 ? 0 : 1; // 0 primero (vencidas)
    const bOver = (b.days_past_due ?? -999999) >= 0 ? 0 : 1;
    if (aOver !== bOver) return aOver - bOver;

    const ad = parseDate(a.due_date) ?? 0;
    const bd = parseDate(b.due_date) ?? 0;
    return ad - bd;
  });

  out.push({ json: g });
}

return out;

function nextBusiness09(fromDate = new Date(), addDays = 2) {
  const d = new Date(fromDate);
  d.setDate(d.getDate() + addDays);
  d.setHours(9, 0, 0, 0);

  const day = d.getDay(); // 0 dom, 6 sab
  if (day === 6) d.setDate(d.getDate() + 2);
  if (day === 0) d.setDate(d.getDate() + 1);

  // Guardamos solo fecha para que haga match con el filtro por dateOnly
  return d.toISOString().slice(0, 10);
}

function normalizeSubject(s) {
  const str = String(s ?? '');
  return str.replace(/^(re:|fw:|fwd:)\s*/i, '').trim();
}

const nowIso = new Date().toISOString();

return $input.all().map((item, index) => {
  const r = $('plantilla mail 1').itemMatching(index).json;

  // Serialización segura para Google Sheets
  const caseKeysArr = Array.isArray(r.case_keys) ? r.case_keys : [];
  const casesArr = Array.isArray(r.cases) ? r.cases : [];

  const case_keys_csv = caseKeysArr.join(',');
  const cases_json = JSON.stringify(casesArr);

  return {
    json: {
      thread_id: r.thread_id,
      billing_address: r.billing_address,
      payer_label: r.payer_label ?? null,
      payer_email: r.payer_email ?? null,
      owner_email: r.owner_email ?? null,

      status_followup: "WAITING_REPLY",
      followup_count: 1,
      next_followup_at: nextBusiness09(new Date(), 2),

      // DRY-RUN ahora; Gmail real luego
      sent_message_id: r.sent_message_id ?? null,
      sent_at: r.sent_at ?? nowIso,

      last_message_id: r.sent_message_id ?? null,
      last_direction: "OUTBOUND",
      last_outbound_at: r.sent_at ?? nowIso,

      last_inbound_at: null,
      last_inbound_from: null,

      subject_normalized: normalizeSubject(r.subject ?? `Recordatorio | Ref: ${r.thread_id}`),
      lock_until: null,

      // Mantener "cases" y "case_keys" pero serializados:
      case_keys: case_keys_csv,
      cases: cases_json,

      created_at: nowIso,
      updated_at: nowIso,

      error: r.error ?? null
    }
  };
});

const nowIso = new Date().toISOString();

return $input.all().flatMap((item, index) => {
  const r = $('plantilla mail 1').itemMatching(index).json;
  const caseKeys = String(r.case_keys || '').split(',').map(s => s.trim()).filter(Boolean);

  return caseKeys.map(k => ({
    json: {
      thread_id: r.thread_id,
      case_key: k,
      is_active: true,
      created_at: nowIso,
      updated_at: nowIso
    }
  }));
});

const ts = $json.timestamp ?? $json.triggerTime ?? new Date().toISOString();
const d = new Date(ts);
const y = d.getFullYear();
const m = String(d.getMonth() + 1).padStart(2, '0');
const day = String(d.getDate()).padStart(2, '0');
const dateOnly = `${y}-${m}-${day}`;

return [{ json: { ...$json, dateOnly } }];

function esc(s){ return String(s ?? ''); }

return $input.all().map(item => {
  const r = item.json;
  const subject = `Re: Recordatorio de facturas pendientes | ${esc(r.payer_label)} | Ref: ${r.thread_id}`;

  const bodyText =
`Hola,

Solo para hacer seguimiento del correo anterior.
¿Podríais confirmarnos el estado y la fecha prevista de pago?

Referencia: ${r.thread_id}

Gracias y un saludo,
Europastry`;

  const bodyHtml = bodyText.replace(/\n/g, '<br/>');

  return { json: { ...r, subject, bodyText, bodyHtml } };
});

function esc(s) {
  return String(s ?? '').replace(/[&<>"']/g, ch => ({
    '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'
  }[ch]));
}
function money(v){
  const n = Number(v);
  return isNaN(n) ? esc(v) : n.toFixed(2);
}

return $input.all().map(item => {
  const r = item.json;

  // Si aún no tienes thread_id generado, crea uno aquí
  // (Mejor hacerlo en un Code node anterior, pero esto te desbloquea)
  const thread_id = r.thread_id ?? `REF-${r.billing_address}-${Date.now()}`;

  const rowsHtml = (r.cases || []).map(c => `
    <tr>
      <td style="padding:6px 8px;border:1px solid #ddd;">${esc(c.document_number)}</td>
      <td style="padding:6px 8px;border:1px solid #ddd;">${esc(c.due_date)}</td>
      <td style="padding:6px 8px;border:1px solid #ddd;text-align:right;">${esc(c.days_past_due)}</td>
      <td style="padding:6px 8px;border:1px solid #ddd;text-align:right;">${money(c.open_amount)}</td>
    </tr>
  `).join('');

  const bodyHtml = `
    <p>Hola,</p>

    <p>Te escribimos desde Europastry porque hemos visto que tenemos las siguientes facturas <b>vencidas</b> y/o <b>próximas a vencer</b>:</p>

    <table style="border-collapse:collapse;font-family:Arial,sans-serif;font-size:13px;">
      <thead>
        <tr>
          <th style="padding:6px 8px;border:1px solid #ddd;background:#f5f5f5;text-align:left;">Documento</th>
          <th style="padding:6px 8px;border:1px solid #ddd;background:#f5f5f5;text-align:left;">Vencimiento</th>
          <th style="padding:6px 8px;border:1px solid #ddd;background:#f5f5f5;text-align:right;">Días</th>
          <th style="padding:6px 8px;border:1px solid #ddd;background:#f5f5f5;text-align:right;">Pendiente</th>
        </tr>
      </thead>
      <tbody>
        ${rowsHtml}
      </tbody>
    </table>

    <p>¿Podríais confirmarnos el estado y la fecha prevista de pago?</p>
    <p><b>Referencia:</b> ${esc(thread_id)}</p>
    <p>Gracias y un saludo,<br/>Europastry</p>
  `;

  // Importante: devolvemos el item, no 1 solo
  return { json: { ...r, thread_id, bodyHtml } };
});

function nextBusinessDate(fromIso, addDays = 2) {
  const d = new Date(fromIso);
  d.setDate(d.getDate() + addDays);
  const day = d.getDay(); // 0 dom, 6 sab
  if (day === 6) d.setDate(d.getDate() + 2);
  if (day === 0) d.setDate(d.getDate() + 1);
  // guardamos solo YYYY-MM-DD
  const y = d.getFullYear();
  const m = String(d.getMonth()+1).padStart(2,'0');
  const dd = String(d.getDate()).padStart(2,'0');
  return `${y}-${m}-${dd}`;
}

return $input.all().map((item, index) => {
  const r = $('plantilla mail 2').itemMatching(index).json;
  const nowIso = r.sent_at ?? new Date().toISOString();

  const newCount = Number(r.followup_count ?? 0) + 1;
  const willClose = newCount >= 5;

  return {
    json: {
      thread_id: r.thread_id,
      followup_count: newCount,
      status_followup: willClose ? "CLOSED" : "WAITING_REPLY",
      last_message_id: r.sent_message_id,
      last_direction: "OUTBOUND",
      billing_address: r.billing_address,
      payer_label: r.payer_label,
      last_outbound_at: nowIso,
      next_followup_at: willClose ? "" : nextBusinessDate(nowIso, 2),
      updated_at: nowIso
    }
  };
});

const nowIso = new Date().toISOString();

return $input.all().flatMap((item, index) => {
  const r = $('plantilla mail 1').itemMatching(index).json;

  // Soporta case_keys como array o como CSV
  const keys = Array.isArray(r.case_keys)
    ? r.case_keys
    : String(r.case_keys || '').split(',').map(s => s.trim()).filter(Boolean);

  return keys.map(k => ({
    json: {
      case_key: k,
      status_followup: "WAITING_REPLY",
      followup_count: 1,
      thread_id: r.thread_id,   // opcional pero recomendado
      updated_at: nowIso
    }
  }));
});

const src = $('Datos para email_threads1').item.json;
const nowIso = src.updated_at ?? new Date().toISOString();

return [{
  json: {
    thread_id: src.thread_id,
    billing_address: src.billing_address ?? "",
    payer_label: src.payer_label ?? "",
    closed_reason: "NO_RESPONSE_5",
    closed_at: nowIso,
    followup_count: src.followup_count,
    notes: "Cierre automático por silencio (5 intentos)",
    created_at: nowIso
  }
}];

// TEST_MODE: ponlo en true para probar fuera de ventana
const TEST_MODE = true;

function ymdLocal(d){
  const y = d.getFullYear();
  const m = String(d.getMonth()+1).padStart(2,'0');
  const day = String(d.getDate()).padStart(2,'0');
  return `${y}-${m}-${day}`;
}

function normalizeDateStr(s){
  if (!s) return null;
  const str = String(s).trim();
  if (/^\d{4}-\d{2}-\d{2}/.test(str)) return str.slice(0,10);
  return null;
}

function isInWindow(now){
  if (TEST_MODE) return true;
  const dow = now.getDay(); // 0 dom, 6 sab
  if (dow === 0 || dow === 6) return false;
  const h = now.getHours();
  return h >= 9 && h < 10;
}

const now = new Date();
const today = ymdLocal(now);

return $input.all().filter(item => {
  const r = item.json;
  if (String(r.status_followup || '') !== 'WAITING_REPLY') return false;

  const fc = Number(r.followup_count ?? 0);
  if (fc >= 5) return false;

  if (!isInWindow(now)) return false;

  const nf = normalizeDateStr(r.next_followup_at);
  if (!nf) return false;

  return nf <= today;
});

// Input: items = rows from Google Sheets credit_cases
const keys = {};
for (const it of items) {
  const k = it.json.case_key;
  if (k) keys[k] = true;
}
return [{ json: { existingKeys: keys } }];

const nowIso = new Date().toISOString();

// Lee existingKeys desde el nodo que lo construye (ajusta el nombre del nodo si es distinto)
const existingKeys =
  ($items("Indexar case_key existentes")[0]?.json?.existingKeys) || {};

return $input.all().map(item => {
  const r = item.json;
  const exists = !!existingKeys[r.case_key];

  const updateRow = {
    case_key: r.case_key,
    billing_address: r.billing_address,
    payer_label: r.payer_label,
    payer_email: r.payer_email,
    owner_name: r.owner_name,
    owner_email: r.owner_email,
    document_number: r.document_number,
    document_type: r.document_type,
    invoice_date: r.invoice_date,
    due_date: r.due_date,
    days_past_due: r.days_past_due,
    aging_bucket: r.aging_bucket,
    open_amount: r.open_amount,
    total_amount: r.total_amount,
    record_type: r.record_type,
    last_status_code: r.last_status_code,
    updated_at: nowIso,
    is_active: true
  };

  return {
    json: {
      exists,
      case_key: r.case_key,
      updateRow,
      insertRow: r
    }
  };
});

// WF01 - construir resumen tras merge (updates + appends)
// Output: 1 item con payload para agent_action_log + email

const nowIso = new Date().toISOString();
const run_id = $execution.id ?? "";  // si tu versión lo soporta

const items = $input.all();

// Intenta contar "updates" y "appends" según de qué rama venga.
// Si tienes nodos separados, lo ideal es marcar action en cada rama antes del merge.
// Como fallback, contamos total.
let updated = 0;
let appended = 0;
let total = items.length;

// Si antes del merge marcaste item.json._op = "UPDATE" / "APPEND", esto funcionará:
for (const it of items) {
  const op = it.json._op;
  if (op === "UPDATE") updated++;
  if (op === "APPEND") appended++;
}

// Si no tienes _op, deja todo como total y 0/0.
const summaryLines = [
  `WF01 (Preparación de casos) completado.`,
  `Timestamp: ${nowIso}`,
  `Total filas procesadas: ${total}`,
  `Actualizadas: ${updated}`,
  `Insertadas: ${appended}`,
];

const emailSubject = `WF01 OK | Preparación de casos | ${nowIso.slice(0,10)}`;
const emailBody =
  summaryLines.join('\n') +
  `\n\n(Entorno PoC - Google Sheets)\n`;

return [{
  json: {
    // agent_action_log payload
    event_id: `WF01-${Date.now()}`,
    timestamp: nowIso,
    run_id,
    action_type: "prepare_cases",
    result: "OK",
    rows_total: total,
    rows_updated: updated,
    rows_inserted: appended,
    error_detail: "",

    // email payload
    notify_to: "diegomendzdln@gmail.com",
    email_subject: emailSubject,
    email_body: emailBody,
  }
}];

const r = $json;

// case_keys llega como CSV desde email_threads
const case_keys = String(r.case_keys || '')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

return [{ json: { ...r, case_keys } }];

