// WF03 - Normaliza salida del LLM (robusto)
// Intenta leer JSON desde varias rutas habituales de n8n OpenAI node

const nowIso = new Date().toISOString();

function tryParseJson(s) {
  if (!s) return null;
  try { return JSON.parse(s); } catch { return null; }
}

const r = $json;

// posibles ubicaciones del texto devuelto por el modelo
const candidate =
  r.output ??
  r.content ??
  r.text ??
  r.message?.content ??
  r.output_text ??
  r.data?.content ??
  null;

// si ya viene como objeto, úsalo
let out = (typeof candidate === "object" && candidate) ? candidate : tryParseJson(candidate);

// fallback: si el nodo ya dejó los campos en raíz
if (!out) out = {
  classification: r.classification,
  next_action: r.next_action,
  routing_team: r.routing_team,
  comment: r.comment,
  confidence: r.confidence,
  payment_date: r.payment_date,
  needs_human: r.needs_human
};

const classification = out.classification ?? "OTHER";
const next_action = out.next_action ?? "FOLLOWUP";
const routing_team = out.routing_team ?? "UNKNOWN";
const comment = out.comment ?? "";
const confidence = (typeof out.confidence === "number") ? out.confidence : 0.5;
const payment_date = out.payment_date ?? null;
const needs_human = (typeof out.needs_human === "boolean") ? out.needs_human : (confidence < 0.6);

return [{
  json: {
    ...r,
    classification,
    next_action,
    routing_team,
    comment,
    confidence,
    payment_date,
    needs_human,
    processed_at: nowIso
  }
}];

const nowIso = $json.processed_at ?? new Date().toISOString();
const isPaid = $json.classification === "PAID_CONFIRMED";

return [{
  json: {
    thread_id: $json.thread_id || $('Get row(s) in sheet').item.json.thread_id,
    status_followup: isPaid ? "CLOSED" : "REPLIED",
    next_followup_at: "",                // importante: pausa silencios
    last_direction: "INBOUND",
    last_inbound_at: nowIso,
    last_inbound_from: $json.from_email ?? "",
    updated_at: nowIso,
    error: ""
  }
}];

function replyText(cls, payment_date) {
  if (cls === "PAID_CONFIRMED") {
    return "Gracias por la confirmación. Quedamos a la espera de validación en sistema. Un saludo.";
  }
  if (cls === "PROMISE_TO_PAY") {
    return payment_date
      ? `Gracias. Tomamos nota del pago previsto para ${payment_date}. Un saludo.`
      : "Gracias. Tomamos nota del pago previsto para los próximos días. Un saludo.";
  }
  if (cls === "DISPUTE") return "Gracias. Revisamos la incidencia indicada y te confirmamos en cuanto tengamos respuesta. Un saludo.";
  if (cls === "NEED_COPY") return "Gracias. Te reenviamos la documentación solicitada en cuanto esté disponible. Un saludo.";
  return "Gracias por tu mensaje. Lo revisamos y te confirmamos a la mayor brevedad. Un saludo.";
}

// en reply_simulated
const nowIso = $json.processed_at ?? new Date().toISOString();

return [{
  json: {
    ...$json,  // ✅ mantiene thread_id, case_keys, classification, etc.
    to_email: $json.from_email ?? "",
    subject: `Re: ${$json.subject ?? ""} | Ref: ${$json.thread_id}`,
    body_text: "Gracias por tu mensaje. Lo revisamos y te confirmamos a la mayor brevedad. Un saludo.",
    created_at: nowIso,
    type: "reply_simulated"
  }
}];

function pickFirst(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

function extractRef(text) {
  if (!text) return null;
  const s = String(text);

  // Captura "Ref: REF-...." o "Referencia: REF-...."
  const m = s.match(/(?:\bref(?:erencia)?\b\s*:\s*)(REF-\S+)/i);
  return m ? m[1] : null;
}

function extractBilling(ref) {
  if (!ref) return null;
  const m = String(ref).match(/REF-(.+)-\d+$/i); // captura todo el tramo intermedio (permite &, ., etc.), hasta el último -<timestamp>
  return m ? m[1] : null;
}

return $input.all().map(item => {
  const r = item.json;

  // Intenta varios caminos típicos del Gmail trigger
  const subject = pickFirst(
    r.subject,
    r.Subject,
    r.payload?.headers?.Subject,
    r.payload?.headers?.subject
  );

  const body = pickFirst(
    r.textPlain,
    r.text,
    r.body,
    r.snippet,
    r.payload?.body?.data
  );

  const thread_id = extractRef(subject) || extractRef(body);

  // Fallback: a veces el Ref está en el subject sin "Ref:" (por ejemplo al reenviar)
  // intenta encontrar REF-xxxx directamente
  const directRef = thread_id || (String(subject).match(/\bREF-\S+/i)?.[0]) || null;

  const billing_address = extractBilling(directRef);

  return {
    json: {
      ...r,
      subject,
      body_text: body,
      thread_id: directRef,
      billing_address
    }
  };
});

function toISODate(v) {
  if (!v) return null;
  if (typeof v === 'string' && /^\d{4}-\d{2}-\d{2}/.test(v)) return v.slice(0, 10);
  const d = new Date(v);
  if (isNaN(d.getTime())) return null;
  return d.toISOString().slice(0, 10);
}

const nowIso = new Date().toISOString();

return items.map((item) => {
  const r = item.json;

  const caseKey =
    r.case_key ??
    `${r.billing_address}|${r.document_number}|${r.document_type}`;

  const payerLabel = r.payer_label ?? r.punto_de_entrega ?? r.punto_contacto_payer ?? null;

  // Normaliza "empty" -> null
  const rawLastStatus = r.last_incidence_management_status ?? null;
  const lastStatus = (rawLastStatus === 'empty' || rawLastStatus === '') ? null : rawLastStatus;

  return {
    json: {
      case_key: caseKey,
      billing_address: r.billing_address ?? null,
      payer_label: payerLabel,

      payer_email: r.punto_contacto_owner_email ?? null,

      owner_name: r.punto_contacto_owner ?? null,
      owner_email: r.punto_contacto_owner_email ?? null,

      document_number: r.document_number ?? null,
      document_type: r.document_type ?? null,
      invoice_date: toISODate(r.invoice_date),
      due_date: toISODate(r.due_date),
      days_past_due: r.days_past_due_date ?? null,
      aging_bucket: r.aging_bucket ?? null,
      open_amount: r.open_amount ?? null,
      total_amount: r.total_amount ?? null,
      record_type: r.record_type ?? null,

      // Defaults for NEW rows (solo deben aplicarse en APPEND, no en UPDATE)
      status_followup: "NEW",
      thread_id: null,
      followup_count: 0,

      last_classification: null,
      last_confidence: null,
      routing_team: null,
      next_action: null,
      last_comment: null,
      last_status_code: lastStatus,

      created_at: nowIso,
      updated_at: nowIso,
      is_active: true
    }
  };
});
